"use client"
import React, { useState } from 'react'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Search, MoreHorizontal, Video } from 'lucide-react'

const contacts = [
    { name: 'Alice Johnson',  online: true,  fallback: 'AJ', color: '#1877f2' },
    { name: 'Bob Smith',      online: true,  fallback: 'BS', color: '#059669' },
    { name: 'Carol White',    online: false, fallback: 'CW', color: '#7c3aed' },
    { name: 'David Lee',      online: true,  fallback: 'DL', color: '#e15241' },
    { name: 'Emma Davis',     online: false, fallback: 'ED', color: '#f59e0b' },
    { name: 'Frank Miller',   online: true,  fallback: 'FM', color: '#0ea5e9' },
    { name: 'Grace Wilson',   online: true,  fallback: 'GW', color: '#ec4899' },
    { name: 'Henry Moore',    online: false, fallback: 'HM', color: '#6366f1' },
    { name: 'Isla Taylor',    online: true,  fallback: 'IT', color: '#14b8a6' },
    { name: 'Jack Anderson',  online: false, fallback: 'JA', color: '#f97316' },
]

const RightSidebar = () => {
    const [searchQuery, setSearchQuery] = useState('')

    const filtered = contacts.filter(c =>
        c.name.toLowerCase().includes(searchQuery.toLowerCase())
    )

    return (
        <aside className="hidden xl:flex flex-col w-70 shrink-0 h-[calc(100vh-56px)] sticky top-14 overflow-y-auto py-3 px-2 scrollbar-hide">

            {/* Sponsored */}
            <div className="mb-3">
                <h3 className="text-[17px] font-semibold text-[#050505] dark:text-[#e4e6eb] px-2 mb-2">Sponsored</h3>
                <div className="flex gap-3 px-2 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl cursor-pointer transition-colors">
                    <div className="w-31 h-31 rounded-xl shrink-0 overflow-hidden bg-linear-to-br from-blue-400 via-purple-500 to-pink-500" />
                    <div className="flex flex-col gap-1 min-w-0">
                        <p className="text-[14px] font-semibold text-[#050505] dark:text-[#e4e6eb] leading-snug">
                            Discover amazing products
                        </p>
                        <p className="text-[12px] text-[#65676b] dark:text-[#b0b3b8]">sponsor.example.com</p>
                        <p className="text-[12px] text-[#65676b] dark:text-[#b0b3b8] leading-snug">
                            Check out our latest deals and exclusive offers!
                        </p>
                    </div>
                </div>
            </div>

            <div className="h-px bg-[#dddfe2] dark:bg-[#3e4042] mx-2 mb-3" />

            {/* Contacts */}
            <div>
                <div className="flex items-center justify-between px-2 mb-2">
                    <h3 className="text-[17px] font-semibold text-[#050505] dark:text-[#e4e6eb]">Contacts</h3>
                    <div className="flex items-center gap-0.5">
                        <button className="p-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-full transition-colors" title="New group video call">
                            <Video className="w-4.5 h-4.5 text-[#65676b] dark:text-[#b0b3b8]" />
                        </button>
                        <button className="p-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-full transition-colors" title="Search contacts">
                            <Search className="w-4.5 h-4.5 text-[#65676b] dark:text-[#b0b3b8]" />
                        </button>
                        <button className="p-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-full transition-colors" title="More options">
                            <MoreHorizontal className="w-4.5 h-4.5 text-[#65676b] dark:text-[#b0b3b8]" />
                        </button>
                    </div>
                </div>

                {/* Search */}
                <div className="relative px-2 mb-2">
                    <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-[#65676b]" />
                    <input
                        type="text"
                        placeholder="Search contacts"
                        value={searchQuery}
                        onChange={e => setSearchQuery(e.target.value)}
                        className="w-full pl-8 pr-3 py-1.5 bg-[#f0f2f5] dark:bg-[#3a3b3c] rounded-full text-[13px] outline-none text-[#050505] dark:text-[#e4e6eb] placeholder-[#65676b] dark:placeholder-[#b0b3b8] focus:ring-2 focus:ring-[#1877f2]/30 transition-all"
                    />
                </div>

                {/* Contact list */}
                <div className="space-y-0.5">
                    {filtered.map((contact) => (
                        <button
                            key={contact.name}
                            className="flex items-center gap-3 px-2 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors w-full text-left"
                        >
                            <div className="relative shrink-0">
                                <Avatar className="w-9 h-9">
                                    <AvatarImage />
                                    <AvatarFallback
                                        className="text-white text-xs font-bold"
                                        style={{ backgroundColor: contact.color }}
                                    >
                                        {contact.fallback}
                                    </AvatarFallback>
                                </Avatar>
                                {contact.online && (
                                    <span className="absolute bottom-0 right-0 w-3 h-3 bg-[#31a24c] border-2 border-white dark:border-[#18191a] rounded-full" />
                                )}
                            </div>
                            <span className="text-[15px] font-medium text-[#050505] dark:text-[#e4e6eb] truncate">
                                {contact.name}
                            </span>
                        </button>
                    ))}
                </div>
            </div>
        </aside>
    )
}

export default RightSidebar
